@Singleton
class CruiseRepository @Inject constructor(
    private val db: AppDatabase,
    private val cruiseDao: CruiseDao,
    private val portOfCallDao: PortOfCallDao,
) {
    fun getAllCruises(): Flow<List<Cruise>> = cruiseDao.getAllCruises()

    fun getCruiseById(id: Long): Flow<Cruise?> = cruiseDao.getCruiseById(id)

    fun getCruiseWithPorts(cruiseId: Long): Flow<CruiseWithPorts?> =
        cruiseDao.getCruiseById(cruiseId).flatMapLatest { cruise ->
            if (cruise == null) {
                flowOf(null)
            } else {
                portOfCallDao.getPortsForCruise(cruiseId).map { ports ->
                    CruiseWithPorts(cruise = cruise, ports = ports)
                }
            }
        }

    /**
     * Saves a cruise, its departure/return ports, and syncs ports of call — all
     * within a single transaction.
     *
     * @param cruise the cruise entity to insert or update
     * @param departurePorts departure and return port entities (replaced each save)
     * @param portsOfCall staged ports of call (new ports have id=0)
     * @param deletedPortIds IDs of ports removed by the user since last load
     * @return the cruise ID (new or existing)
     */
    suspend fun saveCruise(
        cruise: Cruise,
        departurePorts: List<PortOfCall>,
        portsOfCall: List<PortOfCall> = emptyList(),
        deletedPortIds: Set<Long> = emptySet(),
    ): Long = db.withTransaction {
        val savedId = if (cruise.id == 0L) {
            val id = cruiseDao.insert(cruise)
            Timber.i("Inserted cruise: id=%d name=%s", id, cruise.name)
            val portsWithId = departurePorts.map { it.copy(cruiseId = id, id = 0) }
            portOfCallDao.insertAll(portsWithId)
            id
        } else {
            cruiseDao.update(cruise.copy(updatedAt = Instant.now()))
            Timber.i("Updated cruise: id=%d name=%s", cruise.id, cruise.name)
            // Update departure/return ports in place to preserve IDs (and weather data)
            val existingPorts = portOfCallDao.getPortsForCruiseOnce(cruise.id)
            for (newPort in departurePorts) {
                val existing = existingPorts.firstOrNull { it.type == newPort.type }
                if (existing != null) {
                    portOfCallDao.update(newPort.copy(id = existing.id, cruiseId = cruise.id))
                } else {
                    portOfCallDao.insert(newPort.copy(cruiseId = cruise.id, id = 0))
                }
            }
            cruise.id
        }
        // Sync ports of call inside the same transaction
        for (id in deletedPortIds) {
            portOfCallDao.deleteById(id)
        }
        for (port in portsOfCall) {
            if (port.id == 0L) {
                portOfCallDao.insert(port.copy(cruiseId = savedId, id = 0))
            } else {
                portOfCallDao.update(port)
            }
        }
        savedId
    }

    suspend fun deleteCruise(cruise: Cruise) {
        Timber.i("Deleting cruise: id=%d", cruise.id)
        cruiseDao.delete(cruise)
    }

    suspend fun addPortOfCall(port: PortOfCall): Long {
        val id = portOfCallDao.insert(port)
        Timber.i("Inserted port: id=%d cruiseId=%d name=%s", id, port.cruiseId, port.portName)
        return id
    }

    suspend fun updatePortOfCall(port: PortOfCall) {
        Timber.i("Updating port: id=%d name=%s", port.id, port.portName)
        portOfCallDao.update(port)
    }

    suspend fun deletePortOfCall(portId: Long) {
        Timber.i("Deleting port: id=%d", portId)
        portOfCallDao.deleteById(portId)
    }
}
